import { useState, useEffect } from 'react'
import { webAuthnSupported, registerBiometric, hasRegisteredDevice } from '../hooks/useWebAuthn'
import { useNavigate } from 'react-router-dom'
import { useAuth } from '../context/AuthContext'
import LoadingScreen from '../components/LoadingScreen'

const BG = 'data:image/jpeg;base64,'

const LOGO = 'data:image/png;base64,'

const styles = `
  @keyframes l2-borderGlow {
    0%,100% { box-shadow: none; border-color: transparent; }
    50%     { box-shadow: none; border-color: transparent; }
  }
  @keyframes l2-placeholderPulse {
    0%,100% { opacity: 0.45; text-shadow: 0 0 8px rgba(255,255,255,0.20); }
    50%     { opacity: 1.0;  text-shadow: 0 0 14px rgba(255,255,255,0.60), 0 0 30px rgba(255,255,255,0.20); }
  }
  @keyframes l2-iconPulse {
    0%,100% { filter: drop-shadow(0 0 3px rgba(226,226,228,0.25)); opacity: 0.50; }
    50%     { filter: drop-shadow(0 0 10px rgba(226,226,228,0.80)); opacity: 1.0; }
  }
  @keyframes l2-btnGlow {
    0%,100% { box-shadow: 0 0 12px rgba(226,226,228,0.22), 0 0 28px rgba(226,226,228,0.09); }
    50%     { box-shadow: 0 0 24px rgba(226,226,228,0.50), 0 0 56px rgba(226,226,228,0.20), 0 0 90px rgba(226,226,228,0.07); }
  }
  @keyframes l2-btnShine {
    0%   { background-position: -300% center; }
    60%,100% { background-position: 300% center; }
  }
  .l2-input {
    width: 100%;
    box-sizing: border-box;
    background: transparent;
    border: none;
    border-bottom: 1px solid transparent;
    border-radius: 0;
    color: rgba(255,255,255,0.9);
    padding: 13px 14px;
    font-size: 1rem;
    font-family: 'Helvetica Neue', Helvetica, sans-serif;
    outline: none;
    -webkit-appearance: none;
    transition: border-color 0.25s, box-shadow 0.25s;
    caret-color: white;
    box-shadow: none;
  }
  .l2-input:focus {
    background: transparent;
    border-bottom: 1px solid rgba(255,255,255,0.55);
    box-shadow: 0 2px 12px rgba(255,255,255,0.18), 0 1px 4px rgba(255,255,255,0.10);
  }
  .l2-input-icon { padding-left: 36px; }
  .l2-input:-webkit-autofill,
  .l2-input:-webkit-autofill:hover,
  .l2-input:-webkit-autofill:focus {
    -webkit-box-shadow: 0 0 0 1000px rgba(0,0,0,0.88) inset !important;
    -webkit-text-fill-color: rgba(255,255,255,0.9) !important;
    transition: background-color 5000s ease-in-out 0s;
    caret-color: white;
  }
  .l2-input::placeholder {
    color: rgba(255,255,255,1.0);
    font-family: "Helvetica Neue", Helvetica, sans-serif;
    letter-spacing: 0.08em;
    font-size: 0.85rem;
    animation: l2-placeholderPulse 3s ease-in-out infinite;
    text-transform: uppercase;
  }
  .l2-lock-icon {
    animation: l2-iconPulse 3s ease-in-out infinite;
  }
  .l2-enter-btn {
    width: auto;
    display: block;
    margin: 0 auto;
    background: transparent;
    color: rgba(255,255,255,0.25);
    border: none;
    border-radius: 2px;
    padding: 14px;
    font-size: 0.72rem;
    font-weight: 800;
    letter-spacing: 0.3em;
    text-transform: uppercase;
    cursor: pointer;
    font-family: 'Helvetica Neue', Helvetica, sans-serif;
    transition: color 0.4s, text-shadow 0.4s;
    -webkit-appearance: none;
    text-shadow: none;
  }
  .l2-enter-btn.l2-btn-active {
    color: rgba(255,255,255,0.92);
    text-shadow: 0 0 14px rgba(255,255,255,0.5), 0 0 30px rgba(255,255,255,0.2);
    animation: l2-btnGlow 3s ease-in-out infinite, l2-btnShine 4s ease-in-out infinite;
    background-image: linear-gradient(105deg, transparent 35%, rgba(255,255,255,0.07) 50%, transparent 65%);
    background-size: 300% 100%;
  }
  .l2-enter-btn:active { transform: translateY(0); }
  .l2-enter-btn:disabled { opacity: 0.4; cursor: not-allowed; }
`

export default function Login2() {
  const { signIn, user: authUser } = useAuth()
  const navigate = useNavigate()
  const [email, setEmail]       = useState('')
  const [password, setPassword] = useState('')
  const [error, setError]       = useState(null)
  const [loading, setLoading]   = useState(false)
  const [showLoader, setShowLoader]               = useState(false)
  const [offerFaceId, setOfferFaceId]             = useState(false)
  const [registeringFaceId, setRegisteringFaceId] = useState(false)

  useEffect(() => {
    document.body.style.setProperty('background', '#000000', 'important')
    return () => document.body.style.removeProperty('background')
  }, [])

  const handleSubmit = async (e) => {
    e.preventDefault()
    setLoading(true)
    setError(null)
    try {
      const data = await signIn(email, password)
      if (webAuthnSupported() && data?.user) {
        const already = await hasRegisteredDevice(data.user.id)
        if (!already) { setOfferFaceId(true); setLoading(false); return }
      }
      setShowLoader(true)
    } catch (err) {
      setError(err.message)
      setLoading(false)
    }
  }

  const handleRegisterFaceId = async () => {
    setRegisteringFaceId(true)
    try {
      if (authUser) await registerBiometric(authUser)
    } catch (e) { console.error('FaceID:', e.message) }
    finally { setRegisteringFaceId(false); navigate('/dashboard') }
  }

  if (showLoader) return <LoadingScreen onComplete={() => navigate('/dashboard')} />

  return (
    <>
      <style>{styles}</style>
      <div style={{ position: 'fixed', inset: 0, background: '#000' }}>

        {/* Embedded background — full image */}
        <div style={{
          position: 'fixed', inset: 0, zIndex: 0,
          backgroundImage: `url(${BG})`,
          backgroundSize: 'cover',
          backgroundPosition: 'center top',
          backgroundRepeat: 'no-repeat',
        }} />

        {/* Bottom fade — starts higher to frame the full form zone */}
        <div style={{
          position: 'fixed', bottom: 0, left: 0, right: 0, height: '65%', zIndex: 1,
          background: 'linear-gradient(to top, rgba(0,0,0,0.92) 0%, rgba(0,0,0,0.60) 50%, rgba(0,0,0,0) 100%)',
        }} />

        {/* Form — starts at beard line, elements breathe with luxury spacing */}
        <div style={{
          position: 'absolute', zIndex: 10,
          top: '52%',
          left: 0, right: 0,
          padding: '0 2rem',
          maxWidth: '420px',
          margin: '0 auto',
          width: '100%',
          boxSizing: 'border-box',
        }}>
          <form onSubmit={handleSubmit}>

            <div style={{ marginBottom: '2.2rem' }}>
              <div style={{ position: 'relative' }}>
                <svg width="13" height="13" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.8" strokeLinecap="round" strokeLinejoin="round" className="l2-lock-icon" style={{ position: 'absolute', left: '13px', top: '50%', transform: 'translateY(-50%)', color: 'rgba(255,255,255,0.45)', pointerEvents: 'none' }}>
                  <rect x="3" y="11" width="18" height="11" rx="2" ry="2"/>
                  <path d="M7 11V7a5 5 0 0 1 9.9-1"/>
                </svg>
                <input type="email" value={email} onChange={e => setEmail(e.target.value)} placeholder="EMAIL" autoComplete="off" required className="l2-input l2-input-icon" />
                {email.includes('@') && email.includes('.') && (
                  <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round"
                    style={{ position: 'absolute', right: '13px', top: '50%', transform: 'translateY(-50%)', color: 'rgba(255,255,255,0.75)', filter: 'drop-shadow(0 0 6px rgba(255,255,255,0.6))', pointerEvents: 'none' }}>
                    <polyline points="20 6 9 17 4 12"/>
                  </svg>
                )}
              </div>
            </div>

            <div style={{ marginBottom: '3.5rem' }}>
              <div style={{ position: 'relative' }}>
                <svg width="13" height="13" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.8" strokeLinecap="round" strokeLinejoin="round" className="l2-lock-icon" style={{ position: 'absolute', left: '13px', top: '50%', transform: 'translateY(-50%)', color: 'rgba(255,255,255,0.45)', pointerEvents: 'none' }}>
                  <rect x="3" y="11" width="18" height="11" rx="2" ry="2"/>
                  <path d="M7 11V7a5 5 0 0 1 10 0v4"/>
                </svg>
                <input type="password" value={password} onChange={e => setPassword(e.target.value)} placeholder="PASSWORD" autoComplete="current-password" required className="l2-input l2-input-icon" />
              </div>
            </div>

            {error && (
              <p style={{ color: 'rgba(255,100,100,0.85)', fontSize: '0.75rem', marginBottom: '1rem', textAlign: 'center', fontFamily: '"Helvetica Neue", Helvetica, sans-serif' }}>{error}</p>
            )}

            {offerFaceId ? (
              <div style={{ textAlign: 'center' }}>
                <p style={{ color: 'rgba(255,255,255,0.7)', fontSize: '0.75rem', fontFamily: '"Helvetica Neue",sans-serif', marginBottom: '1.2rem', lineHeight: 1.5 }}>Enable Face ID for faster sign-in?</p>
                <button type="button" onClick={handleRegisterFaceId} disabled={registeringFaceId}
                  style={{ width: '100%', padding: '13px', borderRadius: 2, border: 'none', background: '#fff', color: '#000', fontSize: '0.75rem', fontWeight: 700, fontFamily: '"Helvetica Neue",sans-serif', letterSpacing: '0.15em', textTransform: 'uppercase', cursor: 'pointer', marginBottom: 10 }}>
                  {registeringFaceId ? 'Setting up…' : 'Enable Face ID'}
                </button>
                <button type="button" onClick={() => setShowLoader(true)}
                  style={{ width: '100%', padding: '11px', borderRadius: 2, border: '1px solid rgba(255,255,255,0.15)', background: 'transparent', color: 'rgba(255,255,255,0.45)', fontSize: '0.7rem', fontFamily: '"Helvetica Neue",sans-serif', letterSpacing: '0.12em', textTransform: 'uppercase', cursor: 'pointer' }}>
                  Skip for now
                </button>
              </div>
            ) : (
              <button type="submit" disabled={loading} className={`l2-enter-btn${password.length > 0 ? ' l2-btn-active' : ''}`}>
                {loading ? 'Entering...' : 'Secure Access'}
              </button>
            )}

            {/* New Axios logo below Secure Access */}
            <div style={{ textAlign: 'center', marginTop: '2.2rem' }}>
              <img src={LOGO} alt="Axios" style={{
                width: '85%', maxWidth: '320px', opacity: 0.88,
                filter: 'drop-shadow(0 0 10px rgba(220,220,230,0.30)) drop-shadow(0 2px 16px rgba(0,0,0,0.8))',
                display: 'block', margin: '0 auto',
              }} />
            </div>


          </form>
        </div>

        {/* Bottom-right credit */}
        <p style={{
          position: 'fixed', bottom: '1.2rem', right: '1.2rem',
          zIndex: 10,
          color: 'rgba(194,148,56,0.82)',
          fontSize: '0.46rem',
          letterSpacing: '0.14em',
          fontFamily: '"Helvetica Neue", Helvetica, sans-serif',
          textTransform: 'uppercase',
          textShadow: '0 0 8px rgba(194,148,56,0.55), 0 0 18px rgba(194,148,56,0.25)',
          margin: 0,
        }}>
          V. 1.01
        </p>

      </div>
    </>
  )
}
